function useDebouncedCallback(callback, delay) {
  const latest = useRef(callback);
  useEffect(() => {
    latest.current = callback; // refresh every render
  });
  return useMemo(() => {
    let t;
    return (...args) => {
      clearTimeout(t);
      t = setTimeout(() => latest.current(...args), delay); // fresh closure
    };
  }, [delay]);
}
